# Scratch: kapareho ng "if then else if then" block
oras = int(input("Anong oras na? (0-23): "))
if oras < 10:
    print("Magandang umaga!")
elif oras < 17:
    print("Magandang tanghali!")
else:
    print("Magandang gabi!")

